// ============================================================
// Créer 6 sous-dossiers dans le dossier session
// ============================================================
// Arborescence standard Qualiopi :
//   00_Admin        — Convention, convocation, contrats
//   01_Pedagogie    — Programme, supports, ressources
//   02_Emargement   — Feuilles de présence
//   03_Evaluation   — PV positionnement, évaluations acquis
//   04_Satisfaction — PV satisfaction, questionnaires
//   05_Certificats  — Attestations, certificats de réalisation
// ============================================================

const sessionFolderId = $('Créer dossier session').item.json.id;

const sousDossiers = [
  '00_Admin',
  '01_Pedagogie',
  '02_Emargement',
  '03_Evaluation',
  '04_Satisfaction',
  '05_Certificats'
];

// Retourne un item par sous-dossier à créer
// Le node suivant (Google Drive) traitera chaque item
return sousDossiers.map(nom => ({
  json: {
    folder_name: nom,
    parent_folder_id: sessionFolderId,
    session_id: $('Filtrer').item.json.session_id,
    formation_intitule: $('Lire Formation').item.json.intitule,
    formateur_nom: $('Lire Formateur').item.json.nom
  }
}));

// ============================================================
// Préparer le HTML de la convention de formation
// ============================================================
// Lit le template templates/template_convention.html depuis le
// filesystem n8n et remplace les placeholders {{variable}}.
// Le fichier HTML n'est PAS embarqué dans ce workflow.
// ============================================================

const fs = require('fs');
const templatePath = '/data/templates/template_convention.html';
let html = fs.readFileSync(templatePath, 'utf8');

const session = $('Filtrer').item.json;
const formation = $('Lire Formation').item.json;
const formateur = $('Lire Formateur').item.json;
const organisme = $('Lire Organisme').item.json;

// Mapping des placeholders
const replacements = {
  'organisme_nom': organisme.nom || '',
  'organisme_adresse': organisme.adresse || '',
  'organisme_siret': organisme.siret || '',
  'organisme_nda': organisme.nda || '',
  'organisme_representant': organisme.representant || organisme.responsable_qualite || '',
  'formation_intitule': formation.intitule || '',
  'formation_objectifs': formation.objectifs || '',
  'formation_duree': formation.duree_heures || '',
  'formation_modalite': formation.modalite || '',
  'formation_prerequis': formation.prerequis || '',
  'formation_programme': formation.programme || '',
  'formation_tarif': formation.tarif || '',
  'session_id': session.session_id || '',
  'date_debut': session.date_debut || '',
  'date_fin': session.date_fin || '',
  'lieu': session.lieu || '',
  'horaires': session.horaires || '',
  'formateur_nom': formateur.nom || '',
  'formateur_prenom': formateur.prenom || '',
  'formateur_qualite': formateur.qualite || formateur.specialite || '',
  'date_generation': new Date().toLocaleDateString('fr-FR')
};

for (const [key, value] of Object.entries(replacements)) {
  html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
}

return [{ json: { nom_fichier: `Convention_${session.session_id}_${formation.intitule}.pdf`, session_id: session.session_id, admin_folder_id: $('Créer sous-dossiers').first().json.parent_folder_id }, binary: { file: await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), 'index.html', 'text/html') } }];

// ============================================================
// Préparer le HTML de la convocation individuelle
// ============================================================
// Lit le template templates/template_convocation.html depuis le
// filesystem n8n et remplace les placeholders {{variable}}.
// Le fichier HTML n'est PAS embarqué dans ce workflow.
// ============================================================

const fs = require('fs');
const templatePath = '/data/templates/template_convocation.html';
let html = fs.readFileSync(templatePath, 'utf8');

const inscrit = $json;
const session = $('Filtrer').item.json;
const formation = $('Lire Formation').item.json;
const formateur = $('Lire Formateur').item.json;
const organisme = $('Lire Organisme').item.json;

const replacements = {
  'organisme_nom': organisme.nom || '',
  'organisme_adresse': organisme.adresse || '',
  'organisme_siret': organisme.siret || '',
  'organisme_nda': organisme.nda || '',
  'apprenant_nom': inscrit.nom || '',
  'apprenant_prenom': inscrit.prenom || '',
  'apprenant_email': inscrit.email || '',
  'formation_intitule': formation.intitule || '',
  'formation_duree': formation.duree_heures || '',
  'formation_modalite': formation.modalite || '',
  'session_id': session.session_id || '',
  'date_debut': session.date_debut || '',
  'date_fin': session.date_fin || '',
  'lieu': session.lieu || '',
  'horaires': session.horaires || '',
  'formateur_nom': formateur.nom || '',
  'formateur_prenom': formateur.prenom || '',
  'date_generation': new Date().toLocaleDateString('fr-FR')
};

for (const [key, value] of Object.entries(replacements)) {
  html = html.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
}

return [{ json: { ...inscrit, nom_fichier: `Convocation_${session.session_id}_${inscrit.nom}_${inscrit.prenom}.pdf`, session_id: session.session_id, admin_folder_id: $('Préparer Convention').item.json.admin_folder_id }, binary: { file: await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), 'index.html', 'text/html') } }];
